      function CF_1Formula return VARCHAR2 is
  V_DISPLAY CHAR(13);
begin
  
IF :branch_domain_type='10' THEN
	V_DISPLAY:='Περιφερειακού ';
end if;
IF :branch_domain_type='11' THEN
	V_DISPLAY:='Τοπικού ';
end if;

return v_display;

end;

      function CF_SEXFormula return Char is

V_DISPLAY VARCHAR2(100);
V_DATE DATE;
V_REASON VARCHAR2(5);

begin
	

 v_DATE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
			 0,0,'00001','00315','00059'); ---HM/NIA FILAKISHS
	
	
IF :PRODUCT_CODE='00003' THEN
	IF :SEX='Α' THEN
	  V_DISPLAY:='του ασφαλισμένου';
  end if;
  IF :SEX='Θ' THEN
	  V_DISPLAY:='της ασφαλισμένης';
  end if;
END IF;

IF :PRODUCT_CODE='00004' THEN
	IF :SEX='Α' THEN
		IF :DATE_OF_DEATH IS NOT NULL THEN 
	      V_DISPLAY:='του συνταξιούχου';
		ELSIF V_DATE IS NOT NULL THEN 
		  V_DISPLAY:='του συνταξιούχου';
    END IF;
  END IF;
  IF :SEX='Θ' THEN
	  IF :DATE_OF_DEATH IS NOT NULL THEN 
	    V_DISPLAY:='της συνταξιούχου';
	  ELSIF V_DATE IS NOT NULL THEN 
	  	V_DISPLAY:='της συνταξιούχου';
    END IF;
  END IF;
END IF;


return v_display;
end;

      function CF_7Formula return Number is
V_CONDITION VARCHAR2(100);
V_COND_RET  VARCHAR2(5);
V_DISPLAY NUMBER(3);

begin
  IF :CONDITION IS NOT NULL THEN
  	V_CONDITION := :CONDITION ;
    IF INSTR(V_CONDITION,'=',1,1)>0 THEN
    	V_COND_RET := UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'=')+1,LENGTH(V_CONDITION))); 
    ELSIF INSTR(V_CONDITION,'<',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'<')+1,LENGTH(V_CONDITION))));      	
    ELSIF INSTR(V_CONDITION,'>',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'>')+1,LENGTH(V_CONDITION))));  
    ELSIF INSTR(V_CONDITION,'>=',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'>=')+2,LENGTH(V_CONDITION))));
    ELSIF INSTR(V_CONDITION,'<=',1,1)>0 THEN
      V_COND_RET := V_COND_RET ||(UPPER(SUBSTR(V_CONDITION,INSTR(V_CONDITION,'<=')+2,LENGTH(V_CONDITION))));    	   	
    END IF;
    
      V_DISPLAY := TO_NUMBER(V_COND_RET);
  END IF;
  RETURN V_DISPLAY;
  
end;

      function CF_8Formula return Number is
V_DISPLAY CHAR(10);
V_CHR_YEAR VARCHAR2(4);
V_CHR_DAY VARCHAR2(2);
V_CHR_MONTH VARCHAR2(2);
V_NUM NUMBER(4);
begin
  V_CHR_YEAR:=TO_CHAR(:P_BIRTH_DATE_DIR,'RRRR');
  V_CHR_DAY:=TO_CHAR(:P_BIRTH_DATE_DIR,'DD');
  V_CHR_MONTH:=TO_CHAR(:P_BIRTH_DATE_DIR,'MM');
  V_NUM:=TO_NUMBER(V_CHR_YEAR);
  V_NUM:=V_NUM+:CF_7;
  V_DISPLAY:=V_CHR_DAY||'/'||V_CHR_MONTH||'/'||V_NUM;
  RETURN V_DISPLAY;
  
end;

      function CF_2Formula return char is

V_DISPLAY CHAR(10);
V_MONTH   NUMBER;
V_YEAR    NUMBER;
V_DAYS    NUMBER;
V_TMP_DAY NUMBER;
v_prepare_days_code number;
v_notice_days        number;
V_LAST_DATE1  VARCHAR2(10);
V_LAST_DATE   VARCHAR2(10);
V_FACTITIOUS_MONTH   NUMBER;
V_FACTITIOUS_YEAR    NUMBER;
V_SF_DATE            DATE;

CURSOR FIND_LAST_DAYS IS
SELECT sum(PEN_INSURED_DAYS.INSURANCE_DAYS_CALC_FINAL),
       prepare_days_code,
       sum(notice_insurance_days) 
 	FROM PEN_INSURED_DAYS 
 WHERE PEN_INSURED_DAYS.ACC_ACCOUNT_NO= :P_ACC_ACCOUNT_NO_DIR
   AND PEN_INSURED_DAYS.INS_INSURED_ID= :P_INSURED_ID
   AND PEN_INSURED_DAYS.USE_FLG='1'
   AND PEN_INSURED_DAYS.INSURANCE_DAYS_CALC_FINAL IS NOT NULL
   AND YEAR=V_YEAR
   AND MONTH=V_MONTH
group by prepare_days_code;--,notice_insurance_days;

begin
	V_YEAR:=TO_NUMBER(TO_CHAR(:LAST_DAY_MAX_TO_DATE_1_NVL_MON,'RRRR'));
	V_MONTH:=TO_NUMBER(TO_CHAR(:LAST_DAY_MAX_TO_DATE_1_NVL_MON,'MM'));
	
 --	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec :V_MONTH',V_MONTH);
--	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec :V_YEAR',V_YEAR);


	V_FACTITIOUS_YEAR:=TO_NUMBER(TO_CHAR(:P_FACTITIOUS_DATE,'RRRR'));
	V_FACTITIOUS_MONTH:=TO_NUMBER(TO_CHAR(:P_FACTITIOUS_DATE,'MM'));

	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec :P_ACC_ACCOUNT_NO_DIR',:P_ACC_ACCOUNT_NO_DIR);
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec :P_ACC_ACCOUNT_NO',:P_ACC_ACCOUNT_NO);
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec :P_INSURED_ID_IND',:P_INSURED_ID_IND);
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec :P_INSURED_ID',:P_INSURED_ID);
	commit;
  
	OPEN FIND_LAST_DAYS;
	FETCH FIND_LAST_DAYS INTO V_DAYS, v_prepare_days_code, v_notice_days;
	CLOSE FIND_LAST_DAYS;

--	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec :PRIN XTIPISEI',V_MONTH);
--	COMMIT;

	
	V_LAST_DATE1:=TO_CHAR(TO_DATE(1 || '/' ||V_MONTH || '/' || V_YEAR,'DD/MM/RRRR'));
 	V_LAST_DATE:=TO_NUMBER(TO_CHAR(LAST_DAY(V_LAST_DATE1),'DD'));
	

	IF :FIRST_HMEROMHNIA_LHKSHS IS NOT NULL THEN
		V_SF_DATE:=TO_DATE(:FIRST_HMEROMHNIA_LHKSHS,'DD/MM/RRRR');
	ELSE
		V_SF_DATE:=NULL;
	END IF;
	
	/*INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec V_SF_DATE',V_SF_DATE);
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec V_FACTITIOUS_YEAR',V_FACTITIOUS_YEAR);
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec V_FACTITIOUS_MONTH',V_FACTITIOUS_MONTH);
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec V_YEAR',V_YEAR);
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec V_MONTH',V_MONTH);
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec V_DAYS',V_DAYS);
	commit;*/
    	
	IF V_FACTITIOUS_YEAR= V_YEAR AND V_FACTITIOUS_MONTH=V_MONTH THEN
		IF V_SF_DATE IS NOT NULL THEN
			IF V_SF_DATE<=:P_FACTITIOUS_DATE THEN
				IF TO_CHAR(V_SF_DATE,'MM/RRRR')=TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR') THEN
					V_DISPLAY:=TO_CHAR(V_SF_DATE,'MM/RRRR');
				END IF;
				IF TO_CHAR(V_SF_DATE,'MM/RRRR')!=TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR') THEN
			    IF TO_DATE(V_DAYS || '/' ||V_MONTH || '/' || V_YEAR,'DD/MM/RRRR')>:P_FACTITIOUS_DATE THEN
			    	V_DISPLAY:=TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR');
			    ELSE  		
			      V_DISPLAY:=	TO_CHAR(TO_DATE(V_DAYS || '/' ||V_MONTH || '/' || V_YEAR),'MM/RRRR');
	        END IF;
				END IF;
				
			ELSE
				V_DISPLAY:=TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR');
			END IF;
	  ELSE
			IF TO_DATE(V_DAYS || '/' ||V_MONTH || '/' || V_YEAR,'DD/MM/RRRR')>:P_FACTITIOUS_DATE THEN
			  V_DISPLAY:=TO_CHAR(:P_FACTITIOUS_DATE,'MM/RRRR');
			ELSE  		
			  V_DISPLAY:=	TO_CHAR(TO_DATE(V_DAYS || '/' ||V_MONTH || '/' || V_YEAR),'MM/RRRR');
	    END IF;
	  END IF;
	ELSE
	  IF v_notice_days>25 THEN
		  IF V_DAYS<v_notice_days THEN
		    V_TMP_DAY:=ROUND((V_DAYS*V_LAST_DATE)/v_notice_days);
		    V_DISPLAY:=	TO_CHAR(TO_DATE(V_TMP_DAY || '/' ||V_MONTH || '/' || V_YEAR),'MM/RRRR');
	    ELSE
		    V_DISPLAY:=TO_CHAR(:LAST_DAY_MAX_TO_DATE_1_NVL_MON,'MM/RRRR');
	    END IF;
	  ELSE
		  IF V_DAYS<25 THEN
		    V_TMP_DAY:=ROUND((V_DAYS*V_LAST_DATE)/25);
		    V_DISPLAY:=	TO_CHAR(TO_DATE(V_TMP_DAY || '/' ||V_MONTH || '/' || V_YEAR),'MM/RRRR');
	    ELSE
		    V_DISPLAY:=TO_CHAR(:LAST_DAY_MAX_TO_DATE_1_NVL_MON,'MM/RRRR');
	    END IF;
	  END IF;
	END IF;
	
	INSERT INTO ERROR_DEBUG VALUES('JIMP','death dec v_display',v_display);
	commit;
  
	RETURN v_display;--to_char(:P_ACC_ACCOUNT_NO);
  
end;

