      function CF_AGE_REDUCTFormula return Char is

v_DESCR  VARCHAR2(20);-- CHRYS 7/8/2017
v_calc_begin_date_varchar   VARCHAR2(10);

V_DENOM NUMBER;
V_AGE_LIMIT_REDUCTION NUMBER;
V_REDUCTION_FRACTION  VARCHAR2(10);

/*CURSOR cur_pension_type IS
SELECT MONTHS_GAP||'/'||DENOMINATOR	-- CHRYS 7/8/2017
FROM PEN_ACCOUNT_AGE_REDUCTION
WHERE  ACCOUNT_NO = v_calc_begin_date_varchar;
*/

CURSOR AGE_LIMIT_REDUCT_DENOM IS 
SELECT DISTINCT AGE_LIMIT_REDUCTION
FROM PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

begin

v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01636','00653');

OPEN AGE_LIMIT_REDUCT_DENOM;
FETCH AGE_LIMIT_REDUCT_DENOM
INTO V_AGE_LIMIT_REDUCTION;
IF AGE_LIMIT_REDUCT_DENOM%FOUND THEN
	V_DENOM := ROUND(TO_NUMBER(v_calc_begin_date_varchar)/V_AGE_LIMIT_REDUCTION);
ELSE
	V_DENOM := 200;
END IF;

CLOSE AGE_LIMIT_REDUCT_DENOM;

V_REDUCTION_FRACTION := v_calc_begin_date_varchar||'/'||TO_CHAR(V_DENOM);

RETURN V_REDUCTION_FRACTION;
   
END ;

      function CF_YY_MM_DDFormula return Char is

v_DESCR  VARCHAR2(50);
v_calc_begin_date_varchar1   VARCHAR2(10);
v_calc_begin_date_varchar2   VARCHAR2(10);
v_calc_begin_date_varchar3   VARCHAR2(10);

-- CHRYS 28/7/2020
-- CHRYS 28/7/2020
CURSOR	CUR_FIND_PRODINST IS
SELECT 	B.PRODUCT_PER_INSTITUTION_CODE
FROM 		PEN_ACCOUNT A, PEN_QC_PER_PRODINST B
WHERE 	A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND			A.QCPRODINS_QC_PER_PRODINST_CODE = B.QC_PER_PRODINST_CODE;

V_PRODUCT_PER_INSTITUTION_CODE	PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE%TYPE;
V_LABEL		VARCHAR2(100);

-- END CHRYS 28/7/2020

begin

v_calc_begin_date_varchar1 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01636','00640');

v_calc_begin_date_varchar2 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01636','00641');

v_calc_begin_date_varchar3 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01636','00642');

-- CHRYS 21/2/2018
IF   v_calc_begin_date_varchar1 IS NULL AND v_calc_begin_date_varchar2 IS NULL AND v_calc_begin_date_varchar3 IS NULL THEN
	v_calc_begin_date_varchar3 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01633','00635');
 IF  v_calc_begin_date_varchar3 IS NULL THEN
		v_calc_begin_date_varchar3 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01637','00635');
 END IF;	          
END IF;	

V_DESCR :=  v_calc_begin_date_varchar1||' - '||v_calc_begin_date_varchar2||' - '||v_calc_begin_date_varchar3;

/*	
-- CHRYS 28/7/2020
OPEN 	CUR_FIND_PRODINST;
FETCH	CUR_FIND_PRODINST
INTO	V_PRODUCT_PER_INSTITUTION_CODE;
CLOSE	CUR_FIND_PRODINST;

IF V_PRODUCT_PER_INSTITUTION_CODE = 1451 THEN -- GLK
	V_DESCR :=  v_calc_begin_date_varchar3;
ELSE
-- END CHRYS 28/7/2020
	V_DESCR :=  v_calc_begin_date_varchar1||' - '||v_calc_begin_date_varchar2||' - '||v_calc_begin_date_varchar3;
END IF; -- CHRYS 28/7/2020
*/
RETURN V_DESCR;
  
end;

