function CF_27Formula return Char is
V_RESULT varchar2(100); V_VALUE VARCHAR2(50);
CURSOR cur_VALUE IS SELECT A.VALUE FROM PEN_DEC_FACT_TYPES_INSTANCE A, PEN_ACCOUNT B WHERE A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND B.Account_No = :P_Acc_Account_No_DIR AND A.Title_Code = '01069' AND A.Dec_Fact_Type_Code = '00584';
begin
V_RESULT := ' ΜΕ ΠΙΣΤΩΣΗ ΣΕ ΤΡΑΠΕΖΙΚΟ ΛΟΓΑΡΙΑΣΜΟ.';
v_VALUE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND, :P_DT_DECISION_YEAR_SR, :P_DT_DEC_UNIT_CODE_SR, :P_DT_INCR_SEC_NO_SR, '1', 0, 0, '00001', '01069', '00584');
IF V_VALUE IS NOT NULL THEN V_RESULT := ' ΧΩΡΙΣ ΠΙΣΤΩΣΗ.'; END IF;
RETURN V_RESULT;
END;

      function CF_YY_MM_DD_TSMEDEFormula return Char is

v_DESCR  VARCHAR2(50);
v_calc_begin_date_varchar1   VARCHAR2(10);
v_calc_begin_date_varchar2   VARCHAR2(10);
v_calc_begin_date_varchar3   VARCHAR2(10);



begin

v_calc_begin_date_varchar1 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01637','00681');

v_calc_begin_date_varchar2 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01637','00682');

v_calc_begin_date_varchar3 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01637','00683');

V_DESCR :=  v_calc_begin_date_varchar1||' - '||v_calc_begin_date_varchar2||' - '||v_calc_begin_date_varchar3;

RETURN V_DESCR;
  
end;

      function CF_TSMEDE_AMTFormula return Number is

CURSOR 	CUR_INTRODUCTION IS
SELECT     C.INTRODUCTION_CODE
FROM       PEN_ACCOUNT A,
           PEN_QC_PER_PRODINST B,
           PEN_PRODUCT_PER_INSTITUTIONS C
WHERE      A.ACCOUNT_NO  = :P_ACC_ACCOUNT_NO_DIR
AND        A.QCPRODINS_QC_PER_PRODINST_CODE = B.QC_PER_PRODINST_CODE
AND        B.PRODUCT_PER_INSTITUTION_CODE = C.PRODUCT_PER_INSTITUTION_CODE  ;

V_INTRODUCTION		PEN_PRODUCT_PER_INSTITUTIONS.INTRODUCTION_CODE%TYPE;

begin
	COMBAT_DEBUGING('P_ACC_ACCOUNT_NO_DIR='||:P_ACC_ACCOUNT_NO_DIR, 'CHRYS_REPORTS');
	OPEN		CUR_INTRODUCTION;
	FETCH		CUR_INTRODUCTION
	INTO 		V_INTRODUCTION;
	CLOSE		CUR_INTRODUCTION;
	
  IF V_INTRODUCTION in ('00012','00050','00070'
  	                   ,'00150','01050','01150') --13/7/2021 spap mail by aponomes
  	THEN
  	RETURN (1524.60);
  ELSE
  	RETURN 0;
  END IF;
end;

      function CF_224Formula return Number is
