CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;


-- CHRYS 3/6/2021
CURSOR CUR_PERD2 IS
SELECT	AMOUNT
FROM 		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE   ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     CP_CALCULATION_PARAMETER_CODE  IN ('EMPRD', 'PERD2') -- CHRYS 5/10/2021
AND     CC_PER_BE_TYPE_PER_DECINS_UPD = '1';   

V_AMOUNT_PERD2		NUMBER;
--END CHRYS 3/6/2021

begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	  
	-- CHRYS 3/6/2021
	OPEN 	CUR_PERD2;
	FETCH	CUR_PERD2
	INTO 	V_AMOUNT_PERD2;
	CLOSE	CUR_PERD2;
	
	-- END CHRYS 3/6/2021
 
 /* CHRYS 3/6/2021  
  IF NVL(V_01_01_2019,'0') = '1' OR NVL(V_01_10_2019,'0') = '1'
  	 then
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;
END CHRYS 3/6/2021 */

-- CHRYS 3/6/2021
  IF NVL(V_01_01_2019,'0') = '1' 
  	 then
  	return (FALSE);
  END IF;
  
  IF NVL(V_01_10_2019,'0') = '1' AND V_AMOUNT_PERD2 IS NOT NULL THEN 
  	return (TRUE);
  END IF;
  
  IF NVL(V_01_10_2019,'0') = '1' AND V_AMOUNT_PERD2 IS NULL THEN 
  	return (FALSE);
  END IF;

-- END CHRYS 3/6/2021
  return (TRUE);
end;

