function CF_DEPENDENCTY_TYPEFormula return Char is
CURSOR C1 IS SELECT --PEN_DECISION_INSTANCE_DEATH.Dependency_Type --PEN_DECISION_INSTANCE_DEATH.Dependency_Type_Dec PEN_DEPENDANT_TYPES.dependency_name FROM PEN_DECISION_INSTANCE_DEATH, PEN_APPLICATION_INSTANCES, PEN_DEPENDANT_TYPES WHERE PEN_APPLICATION_INSTANCES.Pdta_Application_Year =PEN_DECISION_INSTANCE_DEATH.Pdta_Application_Year AND PEN_APPLICATION_INSTANCES.Pdta_Application_Unit_Code =PEN_DECISION_INSTANCE_DEATH.Pdta_Application_Unit_Code AND PEN_APPLICATION_INSTANCES.Application_Incr_Seq_No =PEN_DECISION_INSTANCE_DEATH.Application_Incr_Seq_No AND PEN_APPLICATION_INSTANCES.Pdta_Document_Type_Appl_Code=PEN_DECISION_INSTANCE_DEATH.Pdta_Document_Type_Appl_Code AND PEN_DEPENDANT_TYPES.dependency_type =PEN_DECISION_INSTANCE_DEATH.Dependency_Type_Dec AND PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO =:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE =:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR =:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID =:P_INSURED_ID ;
L_DESCR VARCHAR2(200); begin OPEN C1; FETCH C1 INTO L_DESCR; CLOSE C1; RETURN (L_DESCR); end;

      function CF_33Formula return Number is
begin
	  ---- 31/05/2021 SPAP ΔΗΜΙΟΥΡΓΗΘΗΚΕ ΑΥΤΗ ΓΙΑ ΝΑ ΑΝΤΙΚΑΤΑΣΤΗΣΕΙ ΤΗΝ CF_22 ΠΟΥ ΥΠΗΡΧΕ ΚΑΠΟΤΕ ΚΑΙ ΑΛΛΑΞΕ ΜΕ ΤΗΝ ΠΡΟΣΘΗΚΗ ΕΛΕΓΧΟΥ ΤΗΣ CF_32 ΠΟΥ ΕΔΩ ΔΕΝ ΤΗΝ ΘΕΛΟΥΜΕ.
	  ---- ΘΕΛΟΥΜΕ ΕΔΩ ΜΟΝΟ ΑΥΤΟ ΤΟ ΑΠΟΤΕΛΕΣΜΑ
	 	RETURN(NVL(:CF_20,0) + NVL(:CF_21,0) + NVL(:CF_19,0)) /* CHRYS 5/7/2021*/ + NVL(:CF_56,0);
end;

      function CF_55Formula return Number is
v_NUM NUMBER;
-- CHRYS 5/7/2021    
CURSOR 	CUR_AMOUNT_DIAFR IS
SELECT 	AMOUNT
FROM 		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE	 	ACC_ACCOUNT_NO =:P_ACC_ACCOUNT_NO_DIR
AND			CP_CALCULATION_PARAMETER_CODE = 'DDIAF'
AND     CC_PER_BE_TYPE_PER_DECINS_UPD = '1';   

begin
	OPEN 	CUR_AMOUNT_DIAFR;
	FETCH CUR_AMOUNT_DIAFR
  INTO 	v_NUM;
  CLOSE CUR_AMOUNT_DIAFR;
                  
  RETURN v_NUM;
END ;

      function CF_56Formula return Number is
-- CHRYS 5/7/2021
begin
   RETURN (NVL(:CF_55,0) * NVL(:P_PERCENTAGE/100,0));
end;

      function M_55FormatTrigger return boolean is

-- CHRYS 3/6/2021
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;

CURSOR CUR_DIAFR IS
SELECT	AMOUNT
FROM 		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE   ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND     CP_CALCULATION_PARAMETER_CODE = 'DDIAF'
AND     CC_PER_BE_TYPE_PER_DECINS_UPD = '1';   

V_AMOUNT_DIAFR		NUMBER;
V_DIAFR						NUMBER;

begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	  
	-- CHRYS 3/6/2021
	V_DIAFR := 0;
	OPEN 	CUR_DIAFR;
	FETCH	CUR_DIAFR
	INTO 	V_AMOUNT_DIAFR;
	IF CUR_DIAFR%FOUND THEN 
		V_DIAFR := 1;
	END IF;
	CLOSE	CUR_DIAFR;
	
	-- END CHRYS 3/6/2021
  IF NVL(V_01_10_2019,'0') = '1'  AND V_DIAFR = 1 THEN --V_AMOUNT_DIAFR IS NOT NULL THEN
  	return (TRUE);
  ELSE
  	return (FALSE);
  END IF;

  return (TRUE);
end;

